// =====================================================
// DECISÃO ROBUSTA (MAPEAMENTO EM MEMÓRIA)
// =====================================================

// 1. Pega os 362 itens da PLANILHA (do nó de transformação)
const itensPlanilha = $("🔄 Transformar dados4").all();

// 2. Pega TODO o banco que veio da busca (pode vir vazio)
const todosNoBanco = $input.all();

// 3. Cria um MAPA do banco pela chapa para busca rápida
const bancoMap = {};
for (const item of todosNoBanco) {
  if (item.json && item.json.chapa) {
    bancoMap[String(item.json.chapa)] = item.json;
  }
}

// 4. Mapeia os 362 registros da planilha gerando a ação correta
return itensPlanilha.map(pItem => {
  const row = pItem.json;
  const chapa = String(row.chapa);
  const dadoBanco = bancoMap[chapa];

  // Se não existe no mapa, é INSERT
  if (!dadoBanco) {
    return {
      json: {
        ...row,
        operation: 'INSERT'
      }
    };
  }

  // Se existe, comparamos campos para ver se precisa de UPDATE
  let hasChanges = false;
  const updateData = {};
  const ignore = ['id', 'created_at', 'updated_at', 'operation'];

  for (const key of Object.keys(row)) {
    if (ignore.includes(key)) continue;

    const valPlanilha = String(row[key] || '').trim();
    const valBanco = String(dadoBanco[key] || '').trim();

    if (valPlanilha !== valBanco) {
      updateData[key] = row[key];
      hasChanges = true;
    }
  }

  return {
    json: {
      chapa: row.chapa,
      operation: hasChanges ? 'UPDATE' : 'SKIP',
      data: hasChanges ? updateData : null
    }
  };
});

const files = $json.files || [];
if (!files.length) throw new Error('Nenhum arquivo encontrado');
return [{ json: files[0] }];

/**
 * MAPEAMENTO DE DADOS ROBUSTO: Planilha (Linha 7) -> Tabela liberation_data
 * FILTRO: Liberação E-COORDINA >= 01/01/2026
 */

function excelSerialToDate(serial) {
  const excelEpoch = new Date(Date.UTC(1899, 11, 30));
  return new Date(excelEpoch.getTime() + Number(serial) * 86400000);
}

function parseDate(value) {
  if (!value || value === "") return null;
  if (value instanceof Date && !isNaN(value)) return value;
  if (typeof value === 'number') return excelSerialToDate(value);
  const str = String(value).trim();
  const dmy = str.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (dmy) {
    const [, d, m, y] = dmy;
    return new Date(Date.UTC(+y, +m - 1, +d));
  }
  const iso = new Date(str);
  return isNaN(iso) ? null : iso;
}

function formatISO(date) {
  return date ? date.toISOString().split('T')[0] : null;
}

// Normalização agressiva para ignorar acentos, espaços e caracteres especiais
function normalizeKey(key) {
  return String(key || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]/g, '');
}

function getField(row, ...variants) {
  const keys = Object.keys(row);
  for (const v of variants) {
    const target = normalizeKey(v);
    // 1. Tenta correspondência exata normalizada
    for (const k of keys) {
      if (normalizeKey(k) === target) return row[k];
    }
    // 2. Tenta correspondência parcial (ex: \"GRD\" em \"GRD.1\" ou \"GRD (Status)\")
    for (const k of keys) {
      if (normalizeKey(k).includes(target)) return row[k];
    }
  }
  return null;
}

const items = $input.all();
const output = [];
const DATA_CORTE = new Date(Date.UTC(2026, 0, 1));

for (const item of items) {
  const row = item.json || {};

  const chapa = String(getField(row, 'MAT', 'MATRICULA', 'CHAPA', 'chapa') || '').trim();
  const nome = String(getField(row, 'NOME', 'NOME COMPLETO', 'nome') || '').trim();

  if (!chapa || !nome || nome.toUpperCase() === 'NOME' || chapa.toUpperCase() === 'MAT') continue;

  const rawLiberacao = getField(row, 'DATA DE LIBERAÇÃO E-COORDINA', 'DATA DE LIBERACAO E-COORDINA', 'liberacao_ecoordin');
  const objDateLiberacao = parseDate(rawLiberacao);

  if (!objDateLiberacao || objDateLiberacao < DATA_CORTE) continue;

  const grdValue = String(getField(row, 'GRD') || '').trim().toUpperCase();
  const statusPlanilha = String(getField(row, 'STATUS CLIENTE', 'STATUS') || '').trim();

  // NOVA REGRA: Se GRD é "OK", força o status para "LIBERADO"
  const statusFinal = (grdValue === 'OK') ? 'LIBERADO' : statusPlanilha;

  const rowData = {
    chapa,
    nome,
    funcao: getField(row, 'FUNÇÃO RM ATUALIZADA', 'FUNCAO', 'CARGO'),
    area: getField(row, 'AREA DE NEGOCIO', 'AREA'),
    cid: getField(row, 'CIP DE LIBERAÇÃO', 'CIP'),
    rh: String(getField(row, 'RH') || '').trim().toUpperCase(),
    saude: String(getField(row, 'SAÚDE', 'SAUDE') || '').trim().toUpperCase(),
    seguranca: String(getField(row, 'SEGURANÇA', 'SEGURANCA') || '').trim().toUpperCase(),
    grd: grdValue,
    obs_grd: getField(row, 'OBSERVAÇÃO GRD', 'OBS'),
    status: statusFinal,
    data_admissao: formatISO(parseDate(getField(row, 'DATA ADMISSÃO', 'ADMISSAO'))),
    liberacao_ecoordin: formatISO(objDateLiberacao),
    envio_cliente: formatISO(parseDate(getField(row, 'ENVIO PARA O CLIENTE', 'ENVIO CLIENTE')))
  };

  output.push({ json: rowData });
}

return output;

// Prepara os dados para a busca no Supabase
const items = $input.all();
const preparedItems = [];

for (const item of items) {
  const rowData = item.json;

  // Cria um objeto com os dados da planilha e o chapa para busca
  preparedItems.push({
    json: {
      chapa: rowData.chapa,
      planilha_data: rowData
    }
  });
}

return preparedItems;
